class Solution:
    def numUniqueEmails(self, emails):
        seen = set()
        for e in emails:
            at = e.index('@')
            local = e[:at]
            domain = e[at + 1:]
            result = ''
            for ch in local:
                if ch == '+':
                    break
                if ch != '.':
                    result += ch
            seen.add(result + '#' + domain)
        return len(seen)

